import{_ as t,a as r,o,ag as a}from"./chunks/framework.Do1Zayaf.js";const p=JSON.parse('{"title":"Shared Repository Model","description":"","frontmatter":{},"headers":[],"relativePath":"devdoc/SharedRepositoryModel.md","filePath":"devdoc/SharedRepositoryModel.md","lastUpdated":1774285611000}'),i={name:"devdoc/SharedRepositoryModel.md"};function s(n,e,l,d,c,h){return o(),r("div",null,e[0]||(e[0]=[a('<h1 id="shared-repository-model" tabindex="-1">Shared Repository Model <a class="header-anchor" href="#shared-repository-model" aria-label="Permalink to &quot;Shared Repository Model&quot;">​</a></h1><p>This guide explains how to use a shared repository model in <strong>HPCC-Platform</strong> where contributors work in the same repository, while branch rulesets protect release-critical branches.</p><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>The shared repository model is designed to:</p><ul><li>Keep collaboration fast by allowing contributors to create branches in the main repository.</li><li>Preserve release quality by preventing direct writes to protected branches.</li><li>Ensure all important changes are reviewed, tested, and traceable through pull requests.</li></ul><h2 id="why-shared-repository-instead-of-forked-model" tabindex="-1">Why Shared Repository Instead of Forked Model? <a class="header-anchor" href="#why-shared-repository-instead-of-forked-model" aria-label="Permalink to &quot;Why Shared Repository Instead of Forked Model?&quot;">​</a></h2><p>Both models are valid, but for HPCC-Platform&#39;s day-to-day team development, a shared repository model is typically more effective.</p><h3 id="shared-repository-model-preferred-for-hpcc-platform" tabindex="-1">Shared Repository Model (preferred for HPCC-Platform) <a class="header-anchor" href="#shared-repository-model-preferred-for-hpcc-platform" aria-label="Permalink to &quot;Shared Repository Model (preferred for HPCC-Platform)&quot;">​</a></h3><ul><li><strong>Single source of truth for active work</strong>: all feature branches live in one repository, making discovery and collaboration easier.</li><li><strong>Faster cross-team iteration</strong>: reviewers and teammates can push follow-up commits to a contributor branch (when allowed by team process) without cross-fork permission friction.</li><li><strong>Simpler CI and branch governance</strong>: one set of rulesets, required checks, and branch protections applies consistently.</li><li><strong>Lower operational overhead</strong>: no need to keep many personal forks synchronized with upstream before every new change.</li><li><strong>Better release discipline with rulesets</strong>: strict controls on <code>master</code> and <code>candidate-*</code> coexist with flexible contributor branches.</li></ul><h3 id="forked-model-useful-in-some-scenarios" tabindex="-1">Forked Model (useful in some scenarios) <a class="header-anchor" href="#forked-model-useful-in-some-scenarios" aria-label="Permalink to &quot;Forked Model (useful in some scenarios)&quot;">​</a></h3><p>Fork-based workflows are often better when:</p><ul><li>Contributions come from a large external/open-source community with unknown trust levels.</li><li>Repository write access should be highly restricted.</li><li>Teams intentionally want strict isolation between contributor branches and the main repository.</li></ul><h3 id="why-hpcc-platform-chooses-shared" tabindex="-1">Why HPCC-Platform Chooses Shared <a class="header-anchor" href="#why-hpcc-platform-chooses-shared" aria-label="Permalink to &quot;Why HPCC-Platform Chooses Shared&quot;">​</a></h3><p>For an internal or tightly coordinated contributor group, shared-repo workflow improves velocity while preserving safety through branch rulesets. In practice, HPCC-Platform gets:</p><ul><li>collaborative development in one place,</li><li>protected integration branches (<code>master</code>, <code>candidate-*</code>), and</li><li>clear review, CI, and merge controls without fork-management overhead.</li></ul><h3 id="why-shared-model-fits-enterprise-environments" tabindex="-1">Why Shared Model Fits Enterprise Environments <a class="header-anchor" href="#why-shared-model-fits-enterprise-environments" aria-label="Permalink to &quot;Why Shared Model Fits Enterprise Environments&quot;">​</a></h3><p>Open-source projects often prefer forks because contributors are external and trust boundaries are broad. Enterprise environments are different: contributors are usually known employees or approved contractors, and governance is centered on controlled in-repo collaboration.</p><p>In enterprise settings, the shared model works well because it provides:</p><ul><li><strong>Centralized identity and access control</strong>: permissions are managed in one repository using teams/roles, not duplicated across many personal forks.</li><li><strong>Stronger compliance and auditability</strong>: approvals, required checks, and branch-protection events are captured in a single governance surface.</li><li><strong>Consistent CI/CD and secret handling</strong>: one pipeline policy and one secure secret boundary reduce operational risk and configuration drift.</li><li><strong>Clear release management</strong>: maintainers can enforce strict controls on <code>master</code> and <code>candidate-*</code> while still allowing fast contributor iteration on feature branches.</li><li><strong>Lower support overhead</strong>: no need to troubleshoot stale forks, missing upstream syncs, or divergent fork settings across many users.</li><li><strong>Better cross-team ownership</strong>: branches are visible and accessible to the team, which improves handoffs, pairing, and continuity during PTO or team changes.</li></ul><h3 id="model-decision-matrix" tabindex="-1">Model Decision Matrix <a class="header-anchor" href="#model-decision-matrix" aria-label="Permalink to &quot;Model Decision Matrix&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Decision Area</th><th>Shared Repository Model</th><th>Forked Model</th><th>Better Fit for Enterprise HPCC-Platform</th></tr></thead><tbody><tr><td>Contributor trust boundary</td><td>Known internal users (employees/approved contractors)</td><td>Unknown or broad external contributor base</td><td>Shared</td></tr><tr><td>Access control</td><td>Centralized in one repo (teams/roles/rulesets)</td><td>Distributed across many forks + upstream PR permissions</td><td>Shared</td></tr><tr><td>Branch governance</td><td>Uniform rulesets for <code>master</code>, <code>candidate-*</code>, and contributor branches</td><td>Harder to enforce consistent branch policy across forks</td><td>Shared</td></tr><tr><td>CI/CD consistency</td><td>One pipeline policy, one required-check baseline</td><td>Possible drift between fork and upstream settings/workflows</td><td>Shared</td></tr><tr><td>Secret management</td><td>Single controlled secret boundary</td><td>More complex with external fork contexts</td><td>Shared</td></tr><tr><td>Compliance/audit trail</td><td>Centralized approvals, checks, and merge events</td><td>More fragmented trail across multiple repos</td><td>Shared</td></tr><tr><td>Operational overhead</td><td>Low (no fork sync management)</td><td>Higher (syncing stale forks, branch drift)</td><td>Shared</td></tr><tr><td>Cross-team collaboration</td><td>Easy branch visibility and shared ownership</td><td>Slower, extra permissions and cross-fork friction</td><td>Shared</td></tr><tr><td>External community intake</td><td>Less ideal at very large open contribution scale</td><td>Strong fit for large OSS ecosystems</td><td>Forked</td></tr><tr><td>Recommended default for HPCC-Platform</td><td>Yes</td><td>Only for specific external-contributor scenarios</td><td>Shared</td></tr></tbody></table><h2 id="repository-roles" tabindex="-1">Repository Roles <a class="header-anchor" href="#repository-roles" aria-label="Permalink to &quot;Repository Roles&quot;">​</a></h2><p>Use two practical role tiers for day-to-day work:</p><ul><li><strong>Collaborators</strong><ul><li>Can write to the repository and create normal feature branches.</li><li>Must use pull requests for integration into protected branches.</li><li>Should not push directly to <code>master</code> or <code>candidate-*</code> branches.</li></ul></li><li><strong>Maintainers</strong><ul><li>Can perform release management tasks.</li><li>Can write to protected branches when needed for approved release operations.</li><li>Own final merge and stabilization decisions.</li></ul></li></ul><h2 id="branch-strategy" tabindex="-1">Branch Strategy <a class="header-anchor" href="#branch-strategy" aria-label="Permalink to &quot;Branch Strategy&quot;">​</a></h2><p>Recommended branch categories for HPCC-Platform:</p><ul><li><strong>Protected integration branches</strong><ul><li><code>master</code></li><li><code>candidate-*</code></li></ul></li><li><strong>Contributor feature branches</strong><ul><li><code>feature/&lt;issue-number&gt;-&lt;short-description&gt;</code></li><li><code>bugfix/&lt;issue-number&gt;-&lt;short-description&gt;</code></li><li><code>docs/&lt;issue-number&gt;-&lt;short-description&gt;</code></li></ul></li></ul><p>Contributors develop on feature branches, open pull requests, and let maintainers control integration into protected branches.</p><h3 id="branch-naming-why-not-username-issue-description" tabindex="-1">Branch Naming: Why Not <code>&lt;username&gt;-&lt;issue&gt;-&lt;description&gt;</code>? <a class="header-anchor" href="#branch-naming-why-not-username-issue-description" aria-label="Permalink to &quot;Branch Naming: Why Not `&lt;username&gt;-&lt;issue&gt;-&lt;description&gt;`?&quot;">​</a></h3><p>A common impulse is to name branches <code>&lt;username&gt;-&lt;issue&gt;-&lt;description&gt;</code> (for example, <code>michael-1234-fix-roxie-crash</code>). While intuitive, this pattern has several drawbacks in a shared repository:</p><ul><li><strong>Type context is lost</strong> — reviewers cannot distinguish a feature branch from a bugfix or documentation change at a glance. Triage and bulk filtering become harder.</li><li><strong>Ruleset pattern matching breaks</strong> — GitHub branch rulesets use glob patterns (<code>feature/**</code>, <code>bugfix/**</code>) to apply different rules per branch category. A flat <code>&lt;username&gt;-*</code> namespace collapses all branch types into one undifferentiated group.</li><li><strong>Authorship is already recorded</strong> — git commit history and the GitHub PR record who created the branch. The username in the branch name is redundant.</li><li><strong>Signals personal ownership</strong> — it discourages collaborators from adding commits to a branch in progress and works against the cooperative intent of the shared repository model.</li><li><strong>Inconsistent with HPCC-Platform&#39;s tracker</strong> — HPCC-Platform uses GitHub Issues. A flat <code>&lt;username&gt;-*</code> prefix obscures the issue number and branch type simultaneously.</li></ul><p><strong>Acceptable compromise (optional):</strong> If author visibility is important to your team, a sub-path layout preserves type prefix while surfacing the author:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>feature/&lt;username&gt;/1234-short-description</span></span>\n<span class="line"><span>bugfix/&lt;username&gt;/1234-short-description</span></span></code></pre></div><p>This keeps ruleset patterns working (<code>feature/**</code>, <code>bugfix/**</code>) and makes the branch owner visible without abandoning branch type context.</p><h2 id="branch-rulesets" tabindex="-1">Branch Rulesets <a class="header-anchor" href="#branch-rulesets" aria-label="Permalink to &quot;Branch Rulesets&quot;">​</a></h2><p>Configure GitHub <strong>Repository Rulesets</strong> to enforce behavior. Use a dedicated ruleset for protected branches.</p><h3 id="ruleset-a-protected-branches-master-candidate" tabindex="-1">Ruleset A: Protected Branches (<code>master</code>, <code>candidate-*</code>) <a class="header-anchor" href="#ruleset-a-protected-branches-master-candidate" aria-label="Permalink to &quot;Ruleset A: Protected Branches (`master`, `candidate-*`)&quot;">​</a></h3><p><strong>Target branches</strong></p><ul><li><code>master</code></li><li><code>candidate-*</code></li></ul><p><strong>Enforcement (recommended)</strong></p><ul><li>Restrict direct pushes.</li><li>Require pull requests before merging.</li><li>Require at least one approving review.</li><li>Require status checks to pass.</li><li>Require branch to be up to date before merging.</li><li>Block force pushes.</li><li>Block branch deletion.</li></ul><p><strong>Bypass / write permissions</strong></p><ul><li>Allow bypass only for the <strong>Maintainers</strong> team (or equivalent role mapping).</li><li>Do <strong>not</strong> include general collaborators in bypass lists.</li></ul><p>This setup satisfies the policy: collaborators can write to the repository, but only maintainers can write directly to <code>master</code> and <code>candidate-*</code>.</p><h3 id="ruleset-b-contributor-branches-optional-hardening" tabindex="-1">Ruleset B: Contributor Branches (optional hardening) <a class="header-anchor" href="#ruleset-b-contributor-branches-optional-hardening" aria-label="Permalink to &quot;Ruleset B: Contributor Branches (optional hardening)&quot;">​</a></h3><p>You may add a second ruleset for contributor branches (for example, <code>feature/**</code>, <code>bugfix/**</code>, <code>docs/**</code>) to prevent accidental force-push or branch deletion if your team prefers stricter controls.</p><h3 id="github-settings-click-path-maintainers" tabindex="-1">GitHub Settings Click Path (Maintainers) <a class="header-anchor" href="#github-settings-click-path-maintainers" aria-label="Permalink to &quot;GitHub Settings Click Path (Maintainers)&quot;">​</a></h3><p>Use this exact click path to configure secure rulesets in GitHub:</p><ol><li>Open the repository: <strong>HPCC-Platform</strong>.</li><li>Click <strong>Settings</strong>.</li><li>In the left sidebar, click <strong>Rules</strong>.</li><li>Click <strong>Rulesets</strong>.</li><li>Click <strong>New ruleset</strong> → <strong>New branch ruleset</strong>.</li></ol><h4 id="configure-ruleset-a-protected-branches" tabindex="-1">Configure Ruleset A (Protected Branches) <a class="header-anchor" href="#configure-ruleset-a-protected-branches" aria-label="Permalink to &quot;Configure Ruleset A (Protected Branches)&quot;">​</a></h4><p>Set the following values:</p><ul><li><strong>Ruleset name</strong>: <code>Protected Integration Branches</code></li><li><strong>Enforcement status</strong>: <code>Active</code></li><li><strong>Target</strong>: <code>Branches</code></li><li><strong>Include by pattern</strong>: <ul><li><code>master</code></li><li><code>candidate-*</code></li></ul></li></ul><p>Enable these rules:</p><ul><li><strong>Restrict updates</strong> (prevents general direct writes)</li><li><strong>Require a pull request before merging</strong><ul><li>Required approvals: at least <code>1</code></li><li>Dismiss stale approvals when new commits are pushed (recommended)</li></ul></li><li><strong>Require status checks to pass</strong><ul><li>Select required checks used by HPCC-Platform CI</li></ul></li><li><strong>Require branches to be up to date before merging</strong></li><li><strong>Block force pushes</strong></li><li><strong>Block deletions</strong></li></ul><p>Set bypass access:</p><ol><li>Find the <strong>Bypass list</strong> (or <strong>Allow specified actors to bypass</strong>).</li><li>Add only the <code>Maintainers</code> team (or equivalent maintainer-only group).</li><li>Confirm no collaborator-level team or broad role is in bypass.</li></ol><p>Save the ruleset.</p><h4 id="configure-ruleset-b-optional-contributor-branch-hardening" tabindex="-1">Configure Ruleset B (Optional Contributor Branch Hardening) <a class="header-anchor" href="#configure-ruleset-b-optional-contributor-branch-hardening" aria-label="Permalink to &quot;Configure Ruleset B (Optional Contributor Branch Hardening)&quot;">​</a></h4><p>Create a second branch ruleset with:</p><ul><li><strong>Ruleset name</strong>: <code>Contributor Branch Guardrails</code></li><li><strong>Enforcement status</strong>: <code>Active</code></li><li><strong>Target</strong>: <code>Branches</code></li><li><strong>Include by pattern</strong>: <ul><li><code>feature/**</code></li><li><code>bugfix/**</code></li><li><code>docs/**</code></li></ul></li></ul><p>Recommended rules:</p><ul><li>Do <strong>not</strong> block force pushes if your team expects contributors to run interactive rebase/squash before merge.</li><li>Block deletion (optional, based on cleanup policy).</li></ul><p>Interactive rebase rewrites branch history, so contributors must be able to force-push their own <code>feature/**</code>, <code>bugfix/**</code>, and <code>docs/**</code> branches after review updates.</p><p>Recommended policy for this workflow:</p><ul><li>Keep force-push blocked on protected branches (<code>master</code>, <code>candidate-*</code>).</li><li>Allow force-push on contributor branches used for active PRs.</li><li>Require final review/sign-off after the squash/rebase push.</li></ul><p>If your team prefers never rewriting branch history, then block force-push on contributor branches and use GitHub&#39;s <strong>Squash and merge</strong> at merge time instead.</p><h4 id="verification-checklist" tabindex="-1">Verification Checklist <a class="header-anchor" href="#verification-checklist" aria-label="Permalink to &quot;Verification Checklist&quot;">​</a></h4><p>After saving rulesets, verify behavior immediately:</p><ol><li>Using a collaborator account, attempt a direct push to <code>master</code> (should be denied).</li><li>Using a collaborator account, open a PR to <code>master</code> (should be allowed).</li><li>Ensure merge is blocked until required review/checks are complete.</li><li>Confirm only maintainers can bypass protections for emergency operations.</li><li>Repeat the direct push test on a <code>candidate-*</code> branch.</li></ol><p>If any test fails, review pattern matching and bypass actor assignments first.</p><h2 id="pull-request-workflow" tabindex="-1">Pull Request Workflow <a class="header-anchor" href="#pull-request-workflow" aria-label="Permalink to &quot;Pull Request Workflow&quot;">​</a></h2><ol><li>Create a branch from the appropriate base (usually <code>master</code>, unless instructed otherwise).</li><li>Commit with clear messages that reference the GitHub issue number (for example, <code>#1234</code>).</li><li>Open a pull request into <code>master</code> or the correct <code>candidate-*</code> branch.</li><li>Ensure all required checks pass.</li><li>Obtain required approvals.</li><li>Maintainer merges according to release policy.</li></ol><h2 id="branch-cleanup-after-merge" tabindex="-1">Branch Cleanup After Merge <a class="header-anchor" href="#branch-cleanup-after-merge" aria-label="Permalink to &quot;Branch Cleanup After Merge&quot;">​</a></h2><p>Contributor branches should be short-lived. After a PR is merged, the branch should be deleted to keep the repository tidy.</p><p>Recommended cleanup approach:</p><ul><li>Enable <strong>Settings → General → Pull Requests → Automatically delete head branches</strong>.</li><li>Keep long-lived branches (<code>master</code>, <code>candidate-*</code>) protected and never treated as cleanup targets.</li><li>If needed, delete merged branches manually from the PR page using <strong>Delete branch</strong>.</li></ul><p>Local cleanup for contributors:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fetch</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --prune</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> branch</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">branch-nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><p>Use <code>git branch -D &lt;branch-name&gt;</code> only when a branch is not fully merged locally but is no longer needed.</p><h2 id="example-day-to-day-development" tabindex="-1">Example: Day-to-Day Development <a class="header-anchor" href="#example-day-to-day-development" aria-label="Permalink to &quot;Example: Day-to-Day Development&quot;">​</a></h2><ul><li>A collaborator creates <code>feature/1234-improve-xyz</code> (where <code>1234</code> is the GitHub issue number).</li><li>The collaborator pushes commits and opens a PR to <code>master</code>.</li><li>GitHub ruleset blocks direct push to <code>master</code> and requires review/checks.</li><li>After approval and green checks, a maintainer merges.</li><li>For release stabilization, maintainers cherry-pick or merge into <code>candidate-*</code> under the same protections.</li></ul><h2 id="operational-guidance-for-maintainers" tabindex="-1">Operational Guidance for Maintainers <a class="header-anchor" href="#operational-guidance-for-maintainers" aria-label="Permalink to &quot;Operational Guidance for Maintainers&quot;">​</a></h2><ul><li>Keep bypass use rare and auditable.</li><li>Prefer normal PR merges even when bypass is technically available.</li><li>Use direct writes only for urgent operational scenarios (for example, release hotfix handling), and document rationale in PR or issue history.</li></ul><h2 id="common-pitfalls" tabindex="-1">Common Pitfalls <a class="header-anchor" href="#common-pitfalls" aria-label="Permalink to &quot;Common Pitfalls&quot;">​</a></h2><ul><li>Giving collaborators bypass permissions on protected branches.</li><li>Allowing direct pushes to <code>candidate-*</code> during stabilization.</li><li>Disabling required checks for convenience.</li><li>Skipping review on high-impact changes.</li></ul><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>In HPCC-Platform, the shared repository model works best when contributors are empowered to work in-repo, while <code>master</code> and <code>candidate-*</code> remain maintainer-controlled through GitHub branch rulesets. This balances development velocity with release safety.</p>',87)]))}const m=t(i,[["render",s]]);export{p as __pageData,m as default};
